insert into public.products (id, data) values ('CB-BRK-PAD', '{"id":"CB-BRK-PAD","name":"Cabler Ceramic Brake Pad Set (Front + Rear)","nameAr":"طقم تيل فرامل سيراميك كابلر (أمامي + خلفي)","brand":"Cabler","category":"Braking","priceUSD":64,"compareAtUSD":79,"rating":0,"reviews":0,"stock":42,"viewing":23,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","BYD","GAC"],"badges":["OEM-Grade","2-Yr Warranty","Fast-Moving"],"accent":"primary","icon":"brake","image":"/parts/brake.svg","descriptionEn":"Full front and rear ceramic brake pad set engineered for quiet, low-dust stopping on Chinese SUVs and sedans. Includes shims and wear sensors where applicable for a clean factory-style fit.","descriptionAr":"طقم كامل من تيل الفرامل السيراميك الأمامي والخلفي مصمم لإيقاف هادئ وأتربة أقل للسيارات الصينية. يشمل العوازل وحساسات التآكل عند الحاجة لتركيب مطابق للمصنع.","highlightsEn":["Ceramic compound for low noise and minimal brake dust","Complete front and rear set in one box","Includes anti-rattle shims and hardware"],"highlightsAr":["خلطة سيراميك لتقليل الصوت وأتربة الفرامل","طقم كامل أمامي وخلفي في علبة واحدة","يشمل العوازل المانعة للاهتزاز وقطع التركيب"],"specs":[{"labelEn":"Material","labelAr":"الخامة","value":"Ceramic"},{"labelEn":"Fitment Position","labelAr":"موضع التركيب","value":"Front + Rear (axle set)"},{"labelEn":"Warranty","labelAr":"الضمان","value":"2 Years / 40,000 km"},{"labelEn":"Pack Contents","labelAr":"محتويات العلبة","value":"8 pads + shims + sensors"},{"labelEn":"Origin","labelAr":"بلد الصنع","value":"China"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-BRK-ROT', '{"id":"CB-BRK-ROT","name":"Cabler Vented Brake Rotor Pair","nameAr":"زوج أقراص فرامل مهواة كابلر","brand":"Cabler","category":"Braking","priceUSD":88,"compareAtUSD":109,"rating":0,"reviews":0,"stock":30,"viewing":17,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","GAC"],"badges":["OEM-Grade","Heat-Rated","2-Yr Warranty"],"accent":"accent","icon":"brake","image":"/parts/brake.svg","descriptionEn":"Pair of vented, anti-corrosion coated brake rotors designed to resist warping under repeated heavy braking. Balanced for smooth, vibration-free stops on GCC roads.","descriptionAr":"زوج من أقراص الفرامل المهواة بطلاء مقاوم للصدأ مصمم لمقاومة الاعوجاج عند الكبح المتكرر الشديد. متوازن لإيقاف سلس بدون اهتزاز على طرقات الخليج.","highlightsEn":["Vented design for faster heat dissipation","Anti-corrosion coating for GCC humidity and dust","Precision-balanced to reduce steering vibration"],"highlightsAr":["تصميم مهوى لتصريف الحرارة بشكل أسرع","طلاء مقاوم للصدأ يناسب رطوبة وغبار الخليج","متوازن بدقة لتقليل اهتزاز المقود"],"specs":[{"labelEn":"Material","labelAr":"الخامة","value":"G3000 cast iron"},{"labelEn":"Type","labelAr":"النوع","value":"Vented disc"},{"labelEn":"Fitment Position","labelAr":"موضع التركيب","value":"Front axle (pair)"},{"labelEn":"Warranty","labelAr":"الضمان","value":"2 Years"},{"labelEn":"Pack Contents","labelAr":"محتويات العلبة","value":"2 rotors"},{"labelEn":"Origin","labelAr":"بلد الصنع","value":"China"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-BAT-12V', '{"id":"CB-BAT-12V","name":"Cabler 12V 72Ah Calcium Car Battery","nameAr":"بطارية سيارة كابلر 12 فولت 72 أمبير كالسيوم","brand":"Cabler","category":"Electrical","priceUSD":119,"compareAtUSD":145,"rating":0,"reviews":0,"stock":24,"viewing":31,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","BYD","GAC"],"badges":["Heat-Rated","2-Yr Warranty","Fast-Moving"],"accent":"success","icon":"battery","image":"/parts/battery.svg","descriptionEn":"Maintenance-free 12V calcium battery built for extreme GCC summer heat with strong cold-cranking power and long service life. Sealed design resists fluid loss in high temperatures for reliable daily starts.","descriptionAr":"بطارية كالسيوم 12 فولت بدون صيانة مصممة لتحمل حرارة صيف الخليج الشديدة مع قدرة تدوير عالية وعمر تشغيلي طويل. تصميم مغلق يقاوم تبخر السائل في درجات الحرارة العالية لتشغيل يومي موثوق.","highlightsEn":["Calcium plates engineered for high-heat GCC climate","Maintenance-free sealed design, no topping up","Strong cold-cranking amps for instant starts"],"highlightsAr":["ألواح كالسيوم مصممة لحرارة الخليج المرتفعة","تصميم مغلق بدون صيانة، لا حاجة لإضافة الماء","أمبير تدوير عالٍ لتشغيل فوري للمحرك"],"specs":[{"labelEn":"Voltage","labelAr":"الجهد","value":"12V"},{"labelEn":"Capacity","labelAr":"السعة","value":"72Ah"},{"labelEn":"Cold Cranking","labelAr":"تيار التدوير البارد","value":"680 CCA"},{"labelEn":"Technology","labelAr":"التقنية","value":"Calcium, maintenance-free"},{"labelEn":"Warranty","labelAr":"الضمان","value":"2 Years"},{"labelEn":"Origin","labelAr":"بلد الصنع","value":"China"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-FIL-AIR', '{"id":"CB-FIL-AIR","name":"Cabler Engine Air Filter","nameAr":"فلتر هواء المحرك من كابلر","brand":"Cabler","category":"Filtration","priceUSD":14.5,"compareAtUSD":19,"rating":0,"reviews":0,"stock":48,"viewing":27,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","BYD","GAC"],"badges":["OEM-Grade","Fast-Moving","Heat-Rated"],"accent":"primary","icon":"filter","image":"/parts/filter.svg","descriptionEn":"High-capacity engine air filter engineered for Gulf desert dust and fine sand. Multi-layer pleated media protects the engine while maintaining strong airflow.","descriptionAr":"فلتر هواء عالي السعة مصمم لمواجهة غبار وأتربة الخليج والرمال الناعمة. وسط مطوي متعدد الطبقات يحمي المحرك مع الحفاظ على تدفق هواء قوي.","highlightsEn":["Captures fine desert dust and sand","High airflow for full engine power","Reinforced frame resists heat warping"],"highlightsAr":["يلتقط غبار ورمال الصحراء الناعمة","تدفق هواء عالٍ لأداء كامل للمحرك","إطار معزز يقاوم التشوه الحراري"],"specs":[{"labelEn":"Filter Media","labelAr":"وسط الترشيح","value":"Multi-layer pleated paper"},{"labelEn":"Fitment Position","labelAr":"موضع التركيب","value":"Engine air intake box"},{"labelEn":"Efficiency","labelAr":"كفاءة الترشيح","value":"99% @ 5 microns"},{"labelEn":"Warranty","labelAr":"الضمان","value":"12 months"},{"labelEn":"Pack Contents","labelAr":"محتويات العبوة","value":"1 air filter"},{"labelEn":"Origin","labelAr":"بلد المنشأ","value":"China"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-FIL-CAB', '{"id":"CB-FIL-CAB","name":"Cabler Cabin AC Filter","nameAr":"فلتر مكيف المقصورة من كابلر","brand":"Cabler","category":"Filtration","priceUSD":11,"compareAtUSD":null,"rating":0,"reviews":0,"stock":55,"viewing":31,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","BYD","GAC"],"badges":["OEM-Grade","Fast-Moving","2-Yr Warranty"],"accent":"accent","icon":"filter","image":"/parts/filter.svg","descriptionEn":"Activated-carbon cabin filter that blocks dust, pollen and odors for cleaner AC air. Keeps the cabin fresh during long, dusty Gulf summers.","descriptionAr":"فلتر مقصورة بالكربون المنشط يحجب الغبار وحبوب اللقاح والروائح لهواء مكيف أنقى. يحافظ على انتعاش المقصورة خلال صيف الخليج الطويل والمغبر.","highlightsEn":["Activated carbon removes odors","Blocks dust, sand and pollen","Improves AC airflow and cooling"],"highlightsAr":["كربون منشط يزيل الروائح","يحجب الغبار والرمل وحبوب اللقاح","يحسن تدفق المكيف والتبريد"],"specs":[{"labelEn":"Filter Media","labelAr":"وسط الترشيح","value":"Activated carbon + non-woven"},{"labelEn":"Fitment Position","labelAr":"موضع التركيب","value":"Behind glove box / HVAC inlet"},{"labelEn":"Function","labelAr":"الوظيفة","value":"Dust, pollen & odor filtration"},{"labelEn":"Warranty","labelAr":"الضمان","value":"24 months"},{"labelEn":"Pack Contents","labelAr":"محتويات العبوة","value":"1 cabin filter"},{"labelEn":"Origin","labelAr":"بلد المنشأ","value":"China"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-FIL-OIL', '{"id":"CB-FIL-OIL","name":"Cabler Engine Oil Filter","nameAr":"فلتر زيت المحرك من كابلر","brand":"Cabler","category":"Filtration","priceUSD":8.5,"compareAtUSD":12,"rating":0,"reviews":0,"stock":60,"viewing":35,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","BYD","GAC"],"badges":["OEM-Grade","Fast-Moving","Heat-Rated"],"accent":"success","icon":"filter","image":"/parts/filter.svg","descriptionEn":"Spin-on engine oil filter with a built-in anti-drainback valve for reliable cold starts. High-flow media keeps oil clean between service intervals.","descriptionAr":"فلتر زيت محرك لولبي مزود بصمام منع الرجوع لضمان تشغيل بارد موثوق. وسط ترشيح عالي التدفق يحافظ على نظافة الزيت بين مواعيد الصيانة.","highlightsEn":["Anti-drainback valve for cold starts","High-flow media protects the engine","Sealed gasket prevents oil leaks"],"highlightsAr":["صمام منع الرجوع لتشغيل بارد سلس","وسط عالي التدفق يحمي المحرك","جوان محكم يمنع تسرب الزيت"],"specs":[{"labelEn":"Filter Type","labelAr":"نوع الفلتر","value":"Spin-on full-flow"},{"labelEn":"Valve","labelAr":"الصمام","value":"Anti-drainback + bypass"},{"labelEn":"Fitment Position","labelAr":"موضع التركيب","value":"Engine oil filter housing"},{"labelEn":"Warranty","labelAr":"الضمان","value":"12 months"},{"labelEn":"Pack Contents","labelAr":"محتويات العبوة","value":"1 oil filter + seal"},{"labelEn":"Origin","labelAr":"بلد المنشأ","value":"China"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-SPK-IRID', '{"id":"CB-SPK-IRID","name":"Iridium Spark Plug Set (4-Pack) — 1.4T/1.5T Turbo","nameAr":"طقم بوجيهات إيريديوم (4 حبات) — لمحركات 1.4T/1.5T تيربو","brand":"Cabler","category":"Engine","priceUSD":38,"compareAtUSD":46,"rating":0,"reviews":0,"stock":52,"viewing":31,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","BYD","GAC"],"badges":["OEM-Grade","Heat-Rated","Fast-Moving"],"accent":"primary","icon":"spark","image":"/parts/spark.svg","descriptionEn":"Fine-wire iridium spark plug set engineered for the high cylinder pressures of 1.4T and 1.5T turbocharged engines. Delivers stable ignition, smoother idle, and reliable cold starts in Gulf heat.","descriptionAr":"طقم بوجيهات إيريديوم بطرف دقيق مصمم لتحمل الضغط العالي في محركات 1.4T و1.5T التيربو. يعطي شرارة ثابتة، تشغيل أنعم، وبدء موثوق حتى في حرارة الخليج.","highlightsEn":["0.6mm fine iridium tip for a strong, consistent spark","Optimized heat range for turbo 1.4T/1.5T engines","Anti-seize coated threads for easy fitting and removal"],"highlightsAr":["طرف إيريديوم دقيق 0.6 ملم لشرارة قوية وثابتة","نطاق حراري مناسب لمحركات التيربو 1.4T و1.5T","أسنان بطلاء مانع للالتصاق لسهولة التركيب والفك"],"specs":[{"labelEn":"Center Electrode","labelAr":"القطب المركزي","value":"Iridium, 0.6mm"},{"labelEn":"Heat Range","labelAr":"النطاق الحراري","value":"Turbo-rated (1.4T / 1.5T)"},{"labelEn":"Gap (Pre-Set)","labelAr":"فتحة الشرارة (مضبوطة مسبقاً)","value":"0.8mm"},{"labelEn":"Pack Contents","labelAr":"محتويات العبوة","value":"4 spark plugs"},{"labelEn":"Warranty","labelAr":"الضمان","value":"12 months"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-AC-COMP', '{"id":"CB-AC-COMP","name":"AC Compressor — Heavy-Duty Max-Cooling","nameAr":"كمبروسر مكيف — تبريد أقصى للعمل الشاق","brand":"Cabler","category":"Cooling","priceUSD":245,"compareAtUSD":289,"rating":0,"reviews":0,"stock":18,"viewing":27,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","GAC"],"badges":["OEM-Grade","2-Yr Warranty","Heat-Rated"],"accent":"accent","icon":"pump","image":"/parts/pump.svg","descriptionEn":"Heavy-duty AC compressor built for constant maximum-cooling duty in Gulf summers. Pre-filled with the correct oil charge and bench-tested for clutch engagement and pressure output.","descriptionAr":"كمبروسر مكيف للخدمة الشاقة مصمم للعمل على أقصى تبريد بشكل مستمر في صيف الخليج. يأتي معبأً بكمية الزيت الصحيحة ومفحوص لضمان عمل القابض وضغط التبريد.","highlightsEn":["Reinforced clutch and bearing for continuous max-cooling load","Pre-charged with PAG oil — ready to install","Each unit pressure-tested before packing"],"highlightsAr":["قابض ومحمل معزز لتحمل حمل التبريد الأقصى المستمر","معبأ مسبقاً بزيت PAG — جاهز للتركيب","كل قطعة مفحوصة بالضغط قبل التغليف"],"specs":[{"labelEn":"Refrigerant","labelAr":"غاز التبريد","value":"R134a compatible"},{"labelEn":"Clutch","labelAr":"القابض","value":"Electromagnetic, reinforced"},{"labelEn":"Oil Charge","labelAr":"شحنة الزيت","value":"PAG, pre-filled"},{"labelEn":"Duty Rating","labelAr":"تصنيف التشغيل","value":"Continuous max-cooling"},{"labelEn":"Warranty","labelAr":"الضمان","value":"24 months"},{"labelEn":"Origin","labelAr":"بلد المنشأ","value":"OEM-grade aftermarket"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-COOL-RAD', '{"id":"CB-COOL-RAD","name":"Radiator with Integrated Water Pump Assembly","nameAr":"رديتر مع طرمبة ماء مدمجة","brand":"Cabler","category":"Cooling","priceUSD":198,"compareAtUSD":null,"rating":0,"reviews":0,"stock":14,"viewing":22,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","GAC"],"badges":["OEM-Grade","2-Yr Warranty","Heat-Rated"],"accent":"success","icon":"pump","image":"/parts/pump.svg","descriptionEn":"Complete cooling solution pairing an aluminum-core radiator with a matched water pump for full coolant circulation. Sized for high ambient temperatures to keep engine temps stable in stop-and-go Gulf traffic.","descriptionAr":"حل تبريد متكامل يجمع رديتر بقلب ألمنيوم مع طرمبة ماء متوافقة لدوران كامل لسائل التبريد. مصمم لتحمل درجات الحرارة العالية للحفاظ على ثبات حرارة المحرك في زحمة الخليج.","highlightsEn":["Aluminum core with high-density fins for fast heat rejection","Matched water pump for balanced coolant flow","Leak-tested seals rated for high-heat operation"],"highlightsAr":["قلب ألمنيوم بزعانف عالية الكثافة لتبريد أسرع","طرمبة ماء متوافقة لتدفق متوازن لسائل التبريد","جوانات مفحوصة ضد التسريب ومصممة للحرارة العالية"],"specs":[{"labelEn":"Core Material","labelAr":"مادة القلب","value":"Aluminum"},{"labelEn":"Pack Contents","labelAr":"محتويات العبوة","value":"Radiator + water pump + gaskets"},{"labelEn":"Tanks","labelAr":"الخزانات","value":"Reinforced composite"},{"labelEn":"Heat Rating","labelAr":"تحمل الحرارة","value":"High-ambient (Gulf-spec)"},{"labelEn":"Warranty","labelAr":"الضمان","value":"24 months"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-SUS-SHOCK', '{"id":"CB-SUS-SHOCK","name":"Front Shock Absorber Strut Pair","nameAr":"زوج مساعدات أمامية (كومبليت)","brand":"Cabler","category":"Suspension","priceUSD":89,"compareAtUSD":109,"rating":0,"reviews":0,"stock":34,"viewing":22,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","BYD","GAC"],"badges":["OEM-Grade","2-Yr Warranty","Fast-Moving"],"accent":"primary","icon":"suspension","image":"/parts/suspension.svg","descriptionEn":"Gas-charged front strut pair engineered for a controlled ride and steady handling on GCC roads. Twin-tube design with consistent damping from cold mornings to summer heat.","descriptionAr":"زوج مساعدات أمامية بضغط الغاز مصمم لراحة أعلى وثبات في القيادة على طرق الخليج. تصميم ثنائي الأنبوب يحافظ على أداء التخميد في البرودة وحرارة الصيف.","highlightsEn":["Gas-charged twin-tube for stable damping","Sold as a matched front pair","Heat-tolerant seals for Gulf climate"],"highlightsAr":["تصميم ثنائي الأنبوب بضغط الغاز لتخميد ثابت","يُباع كزوج أمامي متطابق","حشوات مقاومة لحرارة الخليج"],"specs":[{"labelEn":"Type","labelAr":"النوع","value":"Gas-charged twin-tube"},{"labelEn":"Fitment Position","labelAr":"موضع التركيب","value":"Front axle (left + right)"},{"labelEn":"Pack Contents","labelAr":"محتويات العبوة","value":"2 struts (pair)"},{"labelEn":"Warranty","labelAr":"الضمان","value":"2 years"},{"labelEn":"Origin","labelAr":"بلد الصنع","value":"China"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-SUS-ARM', '{"id":"CB-SUS-ARM","name":"Lower Control Arm & Bushing Kit","nameAr":"طقم مقص سفلي مع الجلب","brand":"Cabler","category":"Suspension","priceUSD":64,"compareAtUSD":79,"rating":0,"reviews":0,"stock":28,"viewing":17,"fitment":["Changan","MG","Geely","Haval","Chery","GAC"],"badges":["OEM-Grade","2-Yr Warranty"],"accent":"accent","icon":"suspension","image":"/parts/suspension.svg","descriptionEn":"Complete lower control arm with pre-pressed bushings and integrated ball joint, ready to bolt on. Restores precise steering and eliminates front-end knocking.","descriptionAr":"مقص سفلي كامل مع جلب مركبة مسبقًا وكرة عمود مدمجة، جاهز للتركيب مباشرة. يعيد دقة التوجيه ويُنهي أصوات الطقطقة في المقدمة.","highlightsEn":["Bushings and ball joint pre-installed","Stamped-steel arm for durability","Direct bolt-on replacement"],"highlightsAr":["الجلب وكرة العمود مركّبة مسبقًا","ذراع من الفولاذ المضغوط لمتانة أعلى","تركيب مباشر بدون تعديل"],"specs":[{"labelEn":"Material","labelAr":"الخامة","value":"Stamped steel arm, rubber bushings"},{"labelEn":"Fitment Position","labelAr":"موضع التركيب","value":"Front lower (per side)"},{"labelEn":"Pack Contents","labelAr":"محتويات العبوة","value":"1 control arm + bushings + ball joint"},{"labelEn":"Warranty","labelAr":"الضمان","value":"2 years"},{"labelEn":"Origin","labelAr":"بلد الصنع","value":"China"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-LGT-HEAD', '{"id":"CB-LGT-HEAD","name":"LED Headlight Assembly Unit","nameAr":"وحدة شمعة أمامية LED","brand":"Cabler","category":"Lighting","priceUSD":135,"compareAtUSD":169,"rating":0,"reviews":0,"stock":19,"viewing":31,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","BYD","GAC"],"badges":["OEM-Grade","Heat-Rated","Fast-Moving"],"accent":"success","icon":"light","image":"/parts/light.svg","descriptionEn":"Plug-and-play LED headlight assembly with crisp white output and a sharp beam cutoff for safe night driving. Sealed housing resists dust and humidity.","descriptionAr":"وحدة شمعة أمامية LED بتركيب مباشر (بلَق آند بلاي) بإضاءة بيضاء واضحة وحد قطع دقيق للرؤية الليلية الآمنة. هيكل محكم يقاوم الغبار والرطوبة.","highlightsEn":["Plug-and-play OEM-style connector","Bright white beam with clean cutoff","Sealed against dust and humidity"],"highlightsAr":["موصل أصلي بتركيب مباشر","شعاع أبيض ساطع بحد قطع نظيف","محكم ضد الغبار والرطوبة"],"specs":[{"labelEn":"Light Source","labelAr":"مصدر الإضاءة","value":"Integrated LED"},{"labelEn":"Color Temperature","labelAr":"درجة حرارة اللون","value":"6000K white"},{"labelEn":"Fitment Position","labelAr":"موضع التركيب","value":"Front headlight (per side)"},{"labelEn":"Pack Contents","labelAr":"محتويات العبوة","value":"1 headlight assembly"},{"labelEn":"Warranty","labelAr":"الضمان","value":"2 years"},{"labelEn":"Origin","labelAr":"بلد الصنع","value":"China"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
insert into public.products (id, data) values ('CB-ENG-BELT', '{"id":"CB-ENG-BELT","name":"Serpentine Drive Belt","nameAr":"سير الدينمو (السير المتعرج)","brand":"Cabler","category":"Engine","priceUSD":22,"compareAtUSD":null,"rating":0,"reviews":0,"stock":52,"viewing":14,"fitment":["Changan","MG","Geely","Jetour","Haval","Chery","BYD","GAC"],"badges":["OEM-Grade","Heat-Rated","Fast-Moving"],"accent":"primary","icon":"belt","image":"/parts/belt.svg","descriptionEn":"Multi-rib serpentine belt made from heat-resistant EPDM rubber for quiet, slip-free power to the alternator, A/C and pumps. Built to last in high-temperature Gulf conditions.","descriptionAr":"سير متعدد الأضلاع مصنوع من مطاط EPDM المقاوم للحرارة لنقل قدرة هادئ وبدون انزلاق للدينمو والمكيف والطلمبات. مصمم ليتحمل أجواء الخليج الحارة.","highlightsEn":["Heat-resistant EPDM construction","Multi-rib design for slip-free grip","Quiet, vibration-damping operation"],"highlightsAr":["تركيب من مطاط EPDM مقاوم للحرارة","تصميم متعدد الأضلاع لمنع الانزلاق","تشغيل هادئ يقلل الاهتزاز"],"specs":[{"labelEn":"Material","labelAr":"الخامة","value":"EPDM rubber"},{"labelEn":"Type","labelAr":"النوع","value":"Multi-rib serpentine"},{"labelEn":"Fitment Position","labelAr":"موضع التركيب","value":"Accessory drive"},{"labelEn":"Pack Contents","labelAr":"محتويات العبوة","value":"1 belt"},{"labelEn":"Warranty","labelAr":"الضمان","value":"2 years"},{"labelEn":"Origin","labelAr":"بلد الصنع","value":"China"}],"gallery":[],"reviewList":[]}'::jsonb) on conflict (id) do update set data = excluded.data;
